import{initTomDropdown as e}from"../../dropdown-item.js";document.addEventListener("DOMContentLoaded",(()=>{document.querySelectorAll('select[data-api$="doy"], select[data-api$="logistes"]').forEach((t=>{const o=`#${t.id}`,n=window.__tomInstances?.[o];n&&(n.destroy(),delete window.__tomInstances[o]);const a=t.dataset.api,s=t.dataset.preselect,d=document.getElementById(s)?.value?.trim();e({selector:o,url:a,extraParams:{},minChars:0}),d&&fetch(`${a}?value=${encodeURIComponent(d)}`).then((e=>e.json())).then((({items:e})=>{if(e?.length){const[t]=e,n=window.__tomInstances?.[o];n&&(n.addOption(t),n.setValue(t.value))}})).catch(console.error)}))}));